    nexacro._indexOf = function (arr, item)
    {
        if (arr == null) return -1;
        var len = arr.length;
        for (var i = 0; i < len; i++)
        {
            if (arr[i] == item)
            {
                return i;
            }
        }
        return -1;
    };

    nexacro._lastIndexOf = function (arr, item)
    {
        if (arr == null) return -1;
        var len = arr.length;
        for (var i = len; i > 0; i--)
        {
            if (arr[i - 1] == item)
            {
                return (i - 1);
            }
        }
        return -1;
    };

