    nexacro._MakeError = function (type, args)
    {
        var _args = Array.prototype.slice.call(args, 1);
        var str = nexacro._getErrorMessge.apply(this, _args);
        var error;
        if (type && (typeof (type) == "function"))
            error = new type(str);
        else
        {
            error = new Error(str);
            error.name = type;
        }

        error.obj = args[0];
        return error;
    };

