        nexacro._getHTMLOuter = function (node, doc)
        {
            if (!node || !node.tagName) return '';
            var txt = node.outerHTML;
            if (!txt)
            {
                var el = doc.createElement("div");

                el.appendChild(node);
                txt = el.innerHTML;
                //                el = null;
            }

            return txt;
        };

