		nexacro._writeTraceLog = function (msglevel, message, bsystemlog, loglevel, traceduration, tracemode)
		{
			var data;
			data = (bsystemlog === true) ? "S" : "U";

			if (msglevel === 0)
				data += "F";
			else if (msglevel == 1)
				data += "E";
			else if (msglevel == 2)
				data += "W";
			else if (msglevel == 3)
				data += "I";
			else
				data += "D";

			var curdate = new nexacro.Date();
			var millisec = curdate.getMilliseconds();

			data = data + " " + curdate.getHours() + ":" + curdate.getMinutes() + ":" + curdate.getSeconds() + ":" + curdate.toZeroDigitString(millisec, 3) + " ";
			var cnt = 16 - data.length;
			for (var i = 0; i < cnt; i++) // match string length 16 byte
				data += " ";

			data += message;

			nexacro.__writeTraceLog(data, loglevel || 4, tracemode || "none", traceduration || -1, msglevel);

			/*  eslint-disable no-console */
			if (console && console.log) console.log(data);
		};

