    {
        if (this._p_tabkeycirculation != v)
        {
            switch (v)
            {
                case "form,nocycle":
                    this._tabkeycirculation = 1;
                    this._p_tabkeycirculation = v;
                    break;
                case "frame,cycle":
                    this._tabkeycirculation = 2;
                    this._p_tabkeycirculation = v;
                    break;
                case "frame,nocycle":
                    this._tabkeycirculation = 3;
                    this._p_tabkeycirculation = v;
                    break;
                default:
                    this._tabkeycirculation = 0;
                    this._p_tabkeycirculation = "form,cycle";
                    break;
            }
        }
    };

