    //"fatal" : 치명적이 에러인 경우 - 0 
    //"error" : 일반적인 에러인 경우 - 1
    //"warn" : 경고인 경우          - 2
    //"info" : 일반 정보인 경우     - 3
    //"debug" : 디버그 정보인 경우  - 4
    _pEnvironment.set_loglevel = function (v)
    {
        if (v == "fatal")
            this._loglevel = 0;
        else if (v == "error")
            this._loglevel = 1;
        else if (v == "warn")
            this._loglevel = 2;
        else if (v == "info")
            this._loglevel = 3;
        else
            this._loglevel = 4;

        this._p_loglevel = v;

        nexacro._setLogLevel(this._loglevel);
    };

