	//==============================================================================
	nexacro._BorderLineObject = function (v)
	{
		if (v && (typeof (v) == "string"))
		{
			var val = v.trim();
			if (val && val.indexOf("none") < 0 && val.indexOf("hidden") < 0)
			{
				this.style = "solid";
				this.value = val;
				this._width = 0;

				var parts = [];
				var cur_idx = 0;
				var next_idx = -1;

				var color_start_idx = -1;
				var color_end_idx = -1;

				var part;

				while (true)
				{
					color_start_idx = this._findColor(val, cur_idx);
					next_idx = val.indexOf(" ", cur_idx);

					if (color_start_idx > 0 && color_start_idx < next_idx)
					{
						color_end_idx = val.indexOf(")", color_start_idx);
						next_idx = val.indexOf(" ", color_end_idx);
					}

					if (next_idx > 0)
					{
						part = val.slice(cur_idx, next_idx);
						cur_idx = next_idx + 1;
					}
					else
					{
						part = val.slice(cur_idx);
						cur_idx = val.length + 1;
					}

					parts[parts.length] = part.trim();

					if (cur_idx >= val.length)
						break;

				}


				//var parts = val.split(/\s+/);
				var cnt = parts.length;
				for (var i = 0; i < cnt; i++)
				{
					var str = parts[i];

					switch (str)
					{
						case "thin":
							if (this.style != "none")
							{
								this.width = str;
								this._width = 1;
							}
							break;
						case "medium":
							if (this.style != "none")
							{
								this.width = str;
								this._width = 3;
							}
							break;
						case "thick":
							if (this.style != "none")
							{
								this.width = str;
								this._width = 5;
							}
							break;

						case "solid":
						case "double":
						case "dotted":
						case "dashed":

						case "groove":
						case "ridge":
						case "inset":
						case "outset":
						case "hidden":
							this.style = str;
							break;

						default:
							if (str.charAt(0) >= '0' && str.charAt(0) <= '9')
							{
								var wv = parseInt(str);
								if (wv == 0)
								{
									this.value = "none";
									this.width = "";
									this._width = 0;
									this.style = "none";
									this.color = "";
									return;
								}
								this.width = wv + "px";
								this._width = wv;
							}
							else
							{
								if (!this.color)
									this.color = nexacro.ColorObject(str);
							}
							break;
					}
				}
			}
		}
	};

