	_pBorderLineObject._findColor = function (str, idx)
	{
		if (!str)
			return -1;

		str = str.toLowerCase();

		var values = ["rgb", "rgba", "hsl", "hsla"];
		var len = values.length;
		var n = -1;
		for (var i = 0; i < len; i++)
		{
			n = str.indexOf(values[i], idx);
			if (n >= 0)
			{
				return n;
			}
		}

		return -1;
	};

