	_pBorderObject._findColor = function (str, idx)
	{
		if (!str)
			return -1;

		str = str.toLowerCase();

		var values = ["rgb", "rgba", "hsl", "hsla"];
		var len = values.length;
		var n = -1;
		var ret = -1;
		for (var i = 0; i < len; i++)
		{
			n = str.indexOf(values[i], idx);
			if (n >= 0)
			{
				if (ret >= 0)
					ret = n < ret ? n : ret;
				else
					ret = n;
			}
		}

		return ret;
	};

