	//==============================================================================
	nexacro._AlignObject = function (v)
	{
		if (v && (typeof (v) == "string"))
		{
			var val = v.trim();
			if (val)
			{
				this.value = val;

				var valarr = val.split(/\s+/);
				for (var i = 0, n = valarr.length; i < n; i++)
				{
					var tok = valarr[i];
					switch (tok)
					{
						case "left":
						case "center":
						case "right":
							this.halign = tok;
							break;
						case "top":
						case "middle":
						case "bottom":
							this.valign = tok;
							break;
					}
				}
			}
		}
	};

