	_pDeviceI.paramck_play = function (strFilePath)
	{
		if (strFilePath == null || typeof (strFilePath) != "string")
		{
			return false;
		}
		var strlength = strFilePath.split(" ").join("");
		if (strlength.length == 0)
		{
			return false;
		}
		return true;
	};
