if (nexacro._macOSWebView)
{
    nexacro.DeviceI.prototype.setup = function ()
    {
		this.curDevice = nexacro._DeviceType.MACOS;
        this._userCreatedObj = {};
    };

    nexacro.DeviceI.prototype.exec = function (jsonstr, sync)
    {
        if (!sync)
            window.webkit.messageHandlers.nexacro.postMessage(jsonstr);
        else
            return prompt("nexacro", jsonstr);
    };

    nexacro._execBrowser = function(strUrl)
    {
        if (strUrl == null)
        {
            return false;
        }

        var params = {
            url: strUrl
        };
        var json = {
            id: "0000",
            div: "Browser",
            method: "execBrowser",
            params: params
        };

        var jsonstr = JSON.stringify(json);
        nexacro.Device.exec(jsonstr);

        return true;
    };

	nexacro._setProtocolVar = function (name, key, val)
    {
        return nexacro.ProtocolAdp.setProtocolVar(name, key, val);
	};

    nexacro._convertRealPath = function (strAlias)
    {
        if (!strAlias)
        {
            return "";
        }

        var params = {
            strAlias: strAlias
        };
        var json = {
            id: "0000",
            div: "AliasPathConverter",
            method: "convertRealPath",
            params: params
        };

        var jsonstr = JSON.stringify(json);
        return nexacro.Device.exec(jsonstr, true);
    };

	nexacro._initDeviceAPI();
};

if (nexacro.ProtocolAdp)
{
	nexacro.ProtocolAdp.isRuntimeProtocol = function (protocol)
	{
		if (!nexacro.ProtocolAdp._isRuntime())
			return false;

		var params = {};

		var option = {
			id: null,		// handle
			div: protocol,	// protocol name
			method: "",     // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	// 0=sync, 1=async
			params: params	// ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__isRuntimeProtocol",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        var result = nexacro.Device.exec(jsonstr, true);

		if (typeof result !== 'object')
			result = nexacro._executeGlobalEvalStr(result);

		return result["result"];
	}

	nexacro.ProtocolAdp.setProtocolVar = function (name, key, val)
	{
		if (!nexacro.ProtocolAdp._isRuntime())
			return;

		var createadaptor = false;
		var protocoladp = nexacro._getProtocol(name);
		if (!protocoladp)
		{
			var isprotocol = nexacro._isProtocol(name);
			if (isprotocol)
			{
				var adptorclass = nexacro._executeGlobalEvalStr(name);
				if (adptorclass)
				{
					protocoladp = new adptorclass;
					createadaptor = true;
				}
			}

			if (!protocoladp)
			{
				if (nexacro.ProtocolAdp.isRuntimeProtocol(name))
				{
					protocoladp = new nexacro.ProtocolAdp;
					protocoladp.protocolname = name;
					createadaptor = true;
				}
			}
		}

		if (protocoladp)
		{
			if (createadaptor && protocoladp.initialize)
			{
				protocoladp.initialize();
				nexacro._addProtocol(name, protocoladp);
			}
		}

		return protocoladp.__setParam(key, val);
	}

	var _pProtocolAdp = nexacro.ProtocolAdp.prototype;

	_pProtocolAdp._p_handle = null;
	_pProtocolAdp._p_protocolname = null;

	_pProtocolAdp._p_librarypath = null;
	_pProtocolAdp._p_classname = null;

	_pProtocolAdp.set_protocolname = function (protocolname)
	{
		this._p_protocolname = protocolname;
	};

	_pProtocolAdp.set_librarypath = function (librarypath)
	{
		this._p_librarypath = librarypath;
	};

	_pProtocolAdp.set_classname = function (classname)
	{
		this._p_classname = classname;
	};

	_pProtocolAdp._properties = [{ name: "handle", readonly: true }, { name: "protocolname" }, { name: "librarypath" }, { name: "classname" }];
    nexacro._defineProperties(_pProtocolAdp, _pProtocolAdp._properties);

	_pProtocolAdp.encrypt = function (strUrl, data)
    {
		if (!nexacro.ProtocolAdp._isRuntime())
			return data;

        return this.__encode(strUrl, data);
    };
    _pProtocolAdp.decrypt = function (strUrl, data)
    {
		if (!nexacro.ProtocolAdp._isRuntime())
        	return data;

		return this.__decode(strUrl, data);
    };

    _pProtocolAdp.initialize = function (strUrl)
    {
		if (!nexacro.ProtocolAdp._isRuntime()) return;

		this.__init(strUrl);
    };
    _pProtocolAdp.finalize = function ()
    {
		if (!nexacro.ProtocolAdp._isRuntime()) return;

		this.__release();
    };
    _pProtocolAdp.getUsingProtocol = function (strUrl)
    {		
		if (!nexacro.ProtocolAdp._isRuntime())
			return "http";

		return this.__getUsingProtocol(strUrl);
    };
    _pProtocolAdp.getCommunicationHeaders = function (strUrl)
    {
		if (!nexacro.ProtocolAdp._isRuntime())
			return [];

		return this.__getHTTPHeader(strUrl);
    };

	_pProtocolAdp.__init = function (strUrl)
	{
		if (!this._p_handle)
			this._p_handle = nexacro.Device.makeID();

		var params = {
			url: strUrl
			// librarypath: this._p_librarypath,
			// classname: this._p_classname
		};

		var option = {
			id: this._p_handle,		    // handle
			div: this._p_protocolname,	// protocol name
			method: "",                 // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	            // 0=sync, 1=async
			params: params	            // ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__init",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        nexacro.Device.exec(jsonstr, true);

		return;
	};

	_pProtocolAdp.__release = function ()
	{
		var params = {};

		var option = {
			id: this._p_handle,		   // handle
			div: this._p_protocolname, // protocol name
			method: "",                // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	           // 0=sync, 1=async
			params: params	           // ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__release",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        nexacro.Device.exec(jsonstr, true);

		return;
	};

	_pProtocolAdp.__setParam  = function (key, value)
	{
		var params = {
            key: key,
            value: value
        };

		var option = {
			id: this._p_handle,		    // handle
			div: this._p_protocolname,	// protocol name
			method: "__setParam",       // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	            // 0=sync, 1=async
			params: params		        // ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__callMethod",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        nexacro.Device.exec(jsonstr, true);

        return true;
	};

	_pProtocolAdp.__encode = function (strUrl, data)
	{
		var is_byte_array = false;
		var inputData = "";
		if (data instanceof Uint8Array)
		{
			inputData = nexacro.ProtocolAdp._toBase64(data);
			is_byte_array = true;
		}
		else
		{
			inputData = nexacro.base64Encode(data);
		}

		var params = {
            url: strUrl,
            input: inputData
        };

		var option = {
			id: this._p_handle,		    // handle
			div: this._p_protocolname,	// protocol name
			method: "__encode",       // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	            // 0=sync, 1=async
			params: params		        // ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__noname",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        var result = nexacro.Device.exec(jsonstr, true);

		if (typeof result !== 'object')
			result = nexacro._executeGlobalEvalStr(result);

		return nexacro.ProtocolAdp._fromBase64(result["output"]);
	};

	_pProtocolAdp.__decode = function (strUrl, data)
	{
		var is_byte_array = false;
		var inputData = "";
		if (data instanceof Uint8Array)
		{
			inputData = nexacro.ProtocolAdp._toBase64(data);
			is_byte_array = true;
		}
		else
		{
			inputData = nexacro.base64Encode(data);
		}

		var params = {
            url: strUrl,
            input: inputData
        };

		var option = {
			id: this._p_handle,		    // handle
			div: this._p_protocolname,	// protocol name
			method: "__decode",       // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	            // 0=sync, 1=async
			params: params		        // ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__noname",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        var result = nexacro.Device.exec(jsonstr, true);

		if (typeof result !== 'object')
			result = nexacro._executeGlobalEvalStr(result);

		return nexacro.ProtocolAdp._fromBase64(result["output"]);
	};

	_pProtocolAdp.__getUsingProtocol = function (strUrl)
	{
		var params = {
			url: strUrl
		};

		var option = {
			id: this._p_handle,		      // handle
			div: this._p_protocolname,	  // protocol name
			method: "__getUsingProtocol", // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	              // 0=sync, 1=async
			params: params		          // ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__noname",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        var result = nexacro.Device.exec(jsonstr, true);

		if (typeof result !== 'object')
			result = nexacro._executeGlobalEvalStr(result);

		return result["result"];
	};

	_pProtocolAdp.__getHTTPHeader = function (strUrl)
	{
		var params = {
			url: strUrl
		};

		var option = {
			id: this._p_handle,		      // handle
			div: this._p_protocolname,	  // protocol name
			method: "__getHTTPHeader", // __setParam, __encode, __decode, __getUsingProtocol, __getHTTPHeader
			async: false,	              // 0=sync, 1=async
			params: params		          // ProtocolAdaptor 라이브러리 함수로 보낼 인자
		};
		
		var json = {
			class: "protocolapi",
			action: "__noname",   // __isRuntimeProtocol / __init / __release
			options: option
		};

        var jsonstr = JSON.stringify(json);
        var result = nexacro.Device.exec(jsonstr, true);

		if (typeof result !== 'object')
			result = nexacro._executeGlobalEvalStr(result);

		return result["result"];
	};

	nexacro.ProtocolAdp._isRuntime = function ()
	{
		let is_runtime = false;
		if (nexacro._OS == "Windows")
		{
			is_runtime = (nexacro._isHybrid && nexacro._isHybrid());
		}
		else if (nexacro._OS == "Mac OS")
		{
			is_runtime = (nexacro._macOSWebView);
		}
		
		return is_runtime;
	}

	if (Uint8Array.prototype.toBase64)
	{
		nexacro.ProtocolAdp._toBase64 = function (bytes)
		{
			return bytes.toBase64();
		}
	}
	else
	{
		nexacro.ProtocolAdp._toBase64 = function (bytes)
		{
			const binString = Array.from(bytes, (x) => String.fromCodePoint(x)).join("");
			return btoa(binString);
		}
	}

	if (Uint8Array.fromBase64)
	{
		nexacro.ProtocolAdp._fromBase64 = function (base64)
		{
			return Uint8Array.fromBase64(base64);
		}
	}
	else
	{
		nexacro.ProtocolAdp._fromBase64 = function (base64)
		{
			const binString = atob(base64);
			return Uint8Array.from(binString, (m) => m.codePointAt(0));
		}
	}

	_pProtocolAdp = null;
};
